/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to an Excel file. LoadWWPContext.Call(&Context)
Do 'OpenDocument'
&CellRow = 1 &FirstColumn = 1
Do 'LoadGridState'
Do 'WriteFilters'
Do 'WriteColumnTitles'
Do 'WriteData'
Do 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportwpLiberacaoPedidos-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&PedCod.IsEmpty() AND &PedLibCliCod.IsEmpty() AND &PedLibSolFun.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Pedido") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &PedCod WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, "Cliente") &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Number = &PedLibCliCod WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 4, "Solic.") &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Number = &PedLibSolFun EndIf If not (&PedLibSts.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Status") If Not &PedLibSts.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &PedLibSts.EnumerationDescription() Endif EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'PEDLIBSOLDTA' &PedLibSolDta1.FromString(&GridStateDynamicFilter.Value) If not &PedLibSolDta1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Solic. > que" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &PedLibSolDta1 EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'PEDLIBSOLDTA' &PedLibSolDta2.FromString(&GridStateDynamicFilter.Value) If not &PedLibSolDta2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Solic. > que" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &PedLibSolDta2 EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'PEDLIBSOLDTA' &PedLibSolDta3.FromString(&GridStateDynamicFilter.Value) If not &PedLibSolDta3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Solic. > que" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &PedLibSolDta3 EndIf EndCase EndIf EndIf EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = "Pedido" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Liberação" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "Data" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "Observação" &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "Solicitante" &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = "Status"
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod FilCod (PedLibSolDta) when &OrderedBy = 1 order PedCod when &OrderedBy = 2 AND &OrderedDsc = False order (PedCod) when &OrderedBy = 2 AND &OrderedDsc = True order PedLibItm when &OrderedBy = 3 AND &OrderedDsc = False order (PedLibItm) when &OrderedBy = 3 AND &OrderedDsc = True order PedLibSolDta when &OrderedBy = 4 AND &OrderedDsc = False order (PedLibSolDta) when &OrderedBy = 4 AND &OrderedDsc = True order PedLibObs when &OrderedBy = 5 AND &OrderedDsc = False order (PedLibObs) when &OrderedBy = 5 AND &OrderedDsc = True order PedLibSolFun when &OrderedBy = 6 AND &OrderedDsc = False order (PedLibSolFun) when &OrderedBy = 6 AND &OrderedDsc = True
using DSwpLiberacaoPedidos(&PedCod, &PedLibCliCod, &PedLibSolFun, &DynamicFiltersSelector1, &PedLibSolDta1, &DynamicFiltersEnabled2 , &DynamicFiltersSelector2, &PedLibSolDta2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &PedLibSolDta3, &PedLibSts)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Number = PedCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = PedLibItm &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Date = PedLibSolDta &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = WWP_Export_SecureText(PedLibObs) &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Number = PedLibSolFun &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = PedLibSts.EnumerationDescription()
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"wpLiberacaoPedidosGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"wpLiberacaoPedidosGridState")) Else &GridState.FromXml(&Session.Get(!"wpLiberacaoPedidosGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"PEDCOD" &PedCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDLIBCLICOD" &PedLibCliCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDLIBSOLFUN" &PedLibSolFun.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDLIBSTS" &PedLibSts.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforeWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

